19	// ── 阶段判定（基于 snippet 文本规则）──
20	function determineStage(entry) {
21	  const snippets = entry.snippet || [];
22	  const allText = snippets.join('\n').toLowerCase();
23	  const lastMsgs = snippets.slice(-6).join('\n').toLowerCase(); // 最近6条
24	  const lastCustMsgs = snippets.filter(s => s.startsWith('[客户]')).slice(-3).join('\n').toLowerCase();
25	  const lastOurMsgs = snippets.filter(s => s.startsWith('[我方]')).slice(-3).join('\n').toLowerCase();
26	
27	  const silence = entry.lastCustomerMsgDays;
28	
29	  // 终态：未成交（客户明确拒绝）
30	  const rejectionPatterns = [
31	    'not interested', 'found another', 'went with', 'too expensive',
32	    '不再需要', '已经找到', '价格太高', '不感兴趣', '取消订单',
33	    'cancel', 'sorry we', 'won\'t be proceeding', 'decided not to',
34	    'pas intéressé', 'trop cher', 'annuler',
35	  ];
36	  const rejected = rejectionPatterns.some(p => lastCustMsgs.includes(p));
37	  if (rejected && silence > 14) return { stage: '未成交', reason: '客户明确拒绝/放弃' };
38	
39	  // 客户表达满意/喜欢 → 已签收信号
40	  const satisfactionPatterns = [
41	    'me encant', 'me gust', 'muy bonito', 'precioso', 'volvería a pedir',
42	    'i love', 'very nice', 'beautiful', 'amazing', 'great quality',
43	    '我很喜欢', '很满意', '不错', '挺好的', '非常好',
44	    'excellent', 'parfait', 'magnifique', 'très bien',
45	    'thank you so much', 'muchas gracias',
46	  ];
47	  const isSatisfied = satisfactionPatterns.some(p => lastCustMsgs.includes(p));
48	
49	  // 已签收 — 优先级高（客户确认收货 或 表达满意）
50	  const deliveredPatterns = ['received', 'delivered', 'arrived', '收到', '已收', 'reçu', 'livré', 'recibido'];
51	  const isDelivered = deliveredPatterns.some(p => lastCustMsgs.includes(p));
52	  if ((isDelivered || isSatisfied) && silence < 90) return { stage: '已签收', reason: isDelivered ? '客户确认收货' : '客户表达满意' };
53	
54	  // 已发货/在途（物流信号，但必须先确认不是已签收）
55	  const shippedPatterns = [
56	    'shipped', 'tracking number', 'on the way', 'in transit',
57	    '已发货', '物流单号', '船期', '航班',
58	    'container', 'vessel', 'eta', 'fedex', 'dhl',
59	    'expédié', 'suivi', 'en transit',
60	    'número de rastreo', 'número de seguimiento', 'enviado',
61	    'ha enviado', 'está en camino', 'ya salió',
62	  ];
63	  const isShipped = shippedPatterns.some(p => lastOurMsgs.includes(p) || lastCustMsgs.includes(p));
64	  if (isShipped && silence < 60) return { stage: '已发货/在途', reason: '对话含物流/发货信号' };
65	
66	  // 售后 — 只扫客户消息，且客户没有表达满意
67	  const afterSalesPatterns = [
68	    'quality issue', 'defect', 'damaged', 'wrong item',
69	    '质量问题', '破损', '退换', '退款', 'refund',
70	    'not as described', 'stain', 'torn', 'broken',
71	    'défaut', 'remboursement', 'defectuoso', 'dañado',
72	    'mala calidad', 'roto', 'manchado',
73	  ];
74	  const isAfterSales = afterSalesPatterns.some(p => lastCustMsgs.includes(p));
75	  if (isAfterSales && !isSatisfied && silence < 30) return { stage: '售后', reason: '客户反馈质量问题' };
76	
77	  // 待付款（PI已发、等付款）
78	  const pendingPaymentPatterns = [
79	    'pi sent', 'proforma', 'invoice sent', 'make payment', 'deposit',
80	    'PI已发', '付款', '定金', '打款', 'invoice', 'tt ',
81	    'waiting for payment', 'bank transfer', 'swift',
82	    'facture', 'paiement', 'acompte',
83	  ];
84	  const isPendingPayment = pendingPaymentPatterns.some(p => lastOurMsgs.includes(p) || lastMsgs.includes(p));
85	  if (isPendingPayment && silence < 30) return { stage: '待付款', reason: 'PI已发/等待付款' };
86	
87	  // 谈判中（价格/数量/规格来回沟通）
88	  const negotiationPatterns = [
89	    'discount', 'cheaper', 'price', 'negotiate', 'best offer',
90	    '折扣', '便宜', '价格', '报价', '最低', '数量', '规格',
91	    'réduction', 'remise', 'prix', 'négocier',
92	  ];
93	  const hasPriceTalk = negotiationPatterns.some(p => lastMsgs.includes(p));
94	  const isBackAndForth = (entry.customerMsgs || 0) >= 3 && (entry.ourMsgs || 0) >= 3;
95	
96	  if (hasPriceTalk && isBackAndForth && silence < 14) {
97	    return { stage: '谈判中', reason: '价格/数量/规格来回沟通' };
98	  }
99	
100	  // 报价已发（我方发了价格，等客户回应）
101	  const quotePatterns = [
102	    'quotation', 'quote', 'fob', '报价', '价格表', 'price list',
103	    'offer', 'catalogue', 'catalog',
104	    'devis', 'offre', 'catalogue',
105	  ];
106	  const hasQuote = quotePatterns.some(p => lastOurMsgs.includes(p));
107	  if (hasQuote && silence < 30) return { stage: '报价已发', reason: '报价已发，等客户回应' };
108	
109	  // 待返单（已签收后的复购窗口）
110	  const reorderPatterns = ['reorder', 'new order', '返单', 'restock', 'again'];
111	  const isReorder = reorderPatterns.some(p => lastCustMsgs.includes(p));
112	  if (isReorder && silence < 60) return { stage: '待返单', reason: '复购信号' };
113	
114	  // 待发货（款已到账，备货中）
115	  const producingPatterns = ['production', 'producing', '备货', '生产中', '安排生产', '排单'];
116	  const isProducing = producingPatterns.some(p => lastOurMsgs.includes(p));
117	  if (isProducing && silence < 30) return { stage: '待发货', reason: '备货/生产中' };
118	
119	  // 长期沉默 → 搁置
120	  if (silence > 30 && entry.customerMsgs <= 3) {
