125	  }
126	
127	  // 默认
128	  if (entry.customerMsgs <= 1 && silence > 14) {
129	    return { stage: '需求探索', reason: '浅互动，客户未深入' };
130	  }
131	  return { stage: '需求探索', reason: '需求沟通阶段' };
132	}
