134	// ── 优先级判定 ──
135	function determinePriority(stage, silence) {
136	  // urgent 条件
137	  if (stage === '待付款' && silence >= 3) return 'now';
138	  if (stage === '售后') return 'now';
139	  if (stage === '谈判中' && silence >= 3 && silence <= 7) return 'now';
140	  if (stage === '报价已发' && silence >= 14 && silence <= 21) return 'now';
141	  if (stage === '已发货/在途' && silence >= 7 && silence <= 14) return 'now';
142	  if (silence === 0 && (stage === '需求探索' || stage === '谈判中')) return 'now';
143	
144	  // soon 条件
145	  if (stage === '待付款' && silence < 3) return 'soon';
146	  if (stage === '谈判中' && silence < 3) return 'soon';
147	  if (stage === '报价已发' && silence >= 7 && silence < 14) return 'soon';
148	  if (stage === '需求探索' && silence >= 3 && silence <= 7) return 'soon';
149	  if (stage === '已发货/在途' && silence < 7) return 'soon';
150	  if (stage === '已签收' && silence < 14) return 'soon';
151	  if (stage === '待发货' && silence < 14) return 'soon';
152	
153	  return 'idle';
154	}
