156	// ── 行动方向 ──
157	function getActionHint(stage, silence, grade, name, entry) {
158	  const d = silence;
159	  const pref = d > 0 ? `⚠静默${d}天，` : '';
160	
161	  switch (stage) {
162	    case '需求探索':
163	      return d > 7 ? `${pref}问需求是否有进展` : `${pref}了解需求，推进报价`;
164	    case '报价已发':
165	      return d > 14 ? `${pref}换策略重联，发新品/行业信息` : `${pref}跟进报价反馈`;
166	    case '谈判中':
167	      return d > 7 ? `${pref}分析卡点，针对性破局` : `${pref}推动决策，解决疑虑`;
168	    case '待付款':
169	      return d > 3 ? `${pref}催付款，确认PI` : `${pref}提醒付款`;
170	    case '待发货':
171	      return d > 7 ? `${pref}同步生产进度` : `${pref}通知发货计划`;
172	    case '已发货/在途':
173	      return d > 7 ? `${pref}跟踪物流，提醒到港` : `${pref}发物流更新`;
174	    case '已签收':
175	      return `${pref}回访满意度，推动复购`;
176	    case '售后':
177	      return `${pref}优先处理投诉`;
178	    case '待返单':
179	      return `${pref}同步新品，争取返单`;
180	    case '搁置':
181	      return d > 90 ? `${pref}暂停触达，等新产品/新认证` : `${pref}直接问"上次那个案子还在推进吗？"`;
182	    case '未成交':
183	      return `${pref}换产品/新切入点重新激活`;
184	    default:
185	      return `${pref}了解需求`;
186	  }
187	}
